CREATE OR REPLACE FUNCTION pg6502.stack_pop()
RETURNS INT AS $$
DECLARE
    v_sp INT;
    v_val INT;
BEGIN
    SELECT sp INTO v_sp FROM pg6502.cpu;
    v_sp := (v_sp + 1) & 255;
    v_val := pg6502.mem_read(256 + v_sp);
    UPDATE pg6502.cpu SET sp = v_sp;
    RETURN v_val;
END
$$ LANGUAGE plpgsql

-- Test for proper cleanup at subtransaction exit.  This example
-- exposed a bug in PG 8.2.

CREATE FUNCTION leaker_1(fail BOOL) RETURNS INTEGER AS $$
DECLARE
  v_var INTEGER;
BEGIN
  BEGIN
    v_var := (leaker_2(fail)).error_code;
  EXCEPTION
    WHEN others THEN RETURN 0;
  END;
  RETURN 1;
END;
$$ LANGUAGE plpgsql

-- INX / DEX / INY / DEY: Increment/decrement registers (implied mode)
CREATE OR REPLACE FUNCTION pg6502.op_inx() RETURNS VOID AS $$
DECLARE v_val INT;
BEGIN
    SELECT (x + 1) & 255 INTO v_val FROM pg6502.cpu;
    UPDATE pg6502.cpu SET x = v_val, pc = pc + 1;
    PERFORM pg6502.set_nz(v_val);
END;
$$ LANGUAGE plpgsql

-- verbose end block and end loop
create function end_label1() returns void as $$
<<blbl>>
begin
  <<flbl1>>
  for i in 1 .. 10 loop
    raise notice 'i = %', i;
    exit flbl1;
  end loop flbl1;
  <<flbl2>>
  for j in 1 .. 10 loop
    raise notice 'j = %', j;
    exit flbl2;
  end loop;
end blbl;
$$ language plpgsql

